import{_ as e,o as d,c as l,ag as a}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Chmod 별칭 | Dotfiles (KO)","titleTemplate":":title","description":"chmod 별칭으로 파일 및 디렉토리 권한 관리를 단순화합니다. 755, 644 등 일반적인 권한 패턴의 빠른 단축키.","frontmatter":{"title":"Chmod 별칭 | Dotfiles","description":"chmod 별칭으로 파일 및 디렉토리 권한 관리를 단순화합니다. 755, 644 등 일반적인 권한 패턴의 빠른 단축키.","lang":"ko-KR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Chmod 별칭 preview","canonical":"/ko/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Chmod 별칭","pageType":"docs","schemaType":"WebPage","metaTitle":"Chmod 별칭 - Dotfiles (KR)","permalink":"/ko/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliases, file permissions, shell shortcuts, dotfiles, unix permissions"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Chmod 별칭 - Dotfiles"},{"name":"twitter:description","content":"chmod 별칭으로 파일 및 디렉토리 권한 관리를 단순화합니다."},{"name":"og:title","content":"Chmod 별칭 - Dotfiles"},{"name":"og:description","content":"chmod 별칭으로 파일 및 디렉토리 권한 관리를 단순화합니다."},{"name":"og:image:alt","content":"Dotfiles - 셸 라이프에 맞게 간단하게 설계됨"},{"name":"og:locale","content":"ko_KR"}]},"headers":[],"relativePath":"ko/aliases/chmod/index.md","filePath":"ko/aliases/chmod/index.md","lastUpdated":1773010926000}'),o={name:"ko/aliases/chmod/index.md"};function i(s,t,r,c,n,h){return d(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="chmod-별칭" tabindex="-1">Chmod 별칭 <a class="header-anchor" href="#chmod-별칭" aria-label="Permalink to &quot;Chmod 별칭&quot;">​</a></h1><p>파일 및 디렉토리 권한 관리를 위한 단축키.</p><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>chmod 별칭은 명령줄에서 파일 및 디렉토리 권한을 관리하는 간소화된 방법을 제공합니다. 숫자 권한 코드를 기억하는 대신 <code>chmod_755</code> 또는 <code>chmod_u+x</code>와 같은 직관적인 별칭을 사용하여 필요한 액세스 모드를 빠르게 설정합니다.</p><p>이 별칭은 <code>chmod.aliases.sh</code>에 정의되어 있으며 chezmoi에 의해 자동으로 로드됩니다.</p><h2 id="참조" tabindex="-1">참조 <a class="header-anchor" href="#참조" aria-label="Permalink to &quot;참조&quot;">​</a></h2><h3 id="일반-권한-별칭" tabindex="-1">일반 권한 별칭 <a class="header-anchor" href="#일반-권한-별칭" aria-label="Permalink to &quot;일반 권한 별칭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">권한</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_000</code></td><td style="text-align:left;"><code>----------</code></td><td style="text-align:left;">모든 사용자에게 권한 없음</td></tr><tr><td style="text-align:left;"><code>chmod_400</code></td><td style="text-align:left;"><code>r--------</code></td><td style="text-align:left;">소유자만 읽기 전용</td></tr><tr><td style="text-align:left;"><code>chmod_444</code></td><td style="text-align:left;"><code>r--r--r--</code></td><td style="text-align:left;">모든 사용자 읽기 전용</td></tr><tr><td style="text-align:left;"><code>chmod_600</code></td><td style="text-align:left;"><code>rw-------</code></td><td style="text-align:left;">소유자만 읽기/쓰기</td></tr><tr><td style="text-align:left;"><code>chmod_644</code></td><td style="text-align:left;"><code>rw-r--r--</code></td><td style="text-align:left;">소유자 읽기/쓰기, 그 외 읽기 전용</td></tr><tr><td style="text-align:left;"><code>chmod_666</code></td><td style="text-align:left;"><code>rw-rw-rw-</code></td><td style="text-align:left;">모든 사용자 읽기/쓰기</td></tr><tr><td style="text-align:left;"><code>chmod_755</code></td><td style="text-align:left;"><code>rwxr-xr-x</code></td><td style="text-align:left;">소유자 전체, 그 외 읽기/실행</td></tr><tr><td style="text-align:left;"><code>chmod_764</code></td><td style="text-align:left;"><code>rwxrw-r--</code></td><td style="text-align:left;">소유자 전체, 그룹 읽기/쓰기</td></tr><tr><td style="text-align:left;"><code>chmod_777</code></td><td style="text-align:left;"><code>rwxrwxrwx</code></td><td style="text-align:left;">모든 사용자 전체 권한</td></tr></tbody></table><h3 id="소유자-권한-별칭" tabindex="-1">소유자 권한 별칭 <a class="header-anchor" href="#소유자-권한-별칭" aria-label="Permalink to &quot;소유자 권한 별칭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_u+x</code></td><td style="text-align:left;">소유자 실행 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_u-x</code></td><td style="text-align:left;">소유자 실행 권한 제거</td></tr><tr><td style="text-align:left;"><code>chmod_u+w</code></td><td style="text-align:left;">소유자 쓰기 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_u-w</code></td><td style="text-align:left;">소유자 쓰기 권한 제거</td></tr><tr><td style="text-align:left;"><code>chmod_u+r</code></td><td style="text-align:left;">소유자 읽기 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_u-r</code></td><td style="text-align:left;">소유자 읽기 권한 제거</td></tr></tbody></table><h3 id="그룹-권한-별칭" tabindex="-1">그룹 권한 별칭 <a class="header-anchor" href="#그룹-권한-별칭" aria-label="Permalink to &quot;그룹 권한 별칭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_g+x</code></td><td style="text-align:left;">그룹 실행 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_g-x</code></td><td style="text-align:left;">그룹 실행 권한 제거</td></tr><tr><td style="text-align:left;"><code>chmod_g+w</code></td><td style="text-align:left;">그룹 쓰기 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_g-w</code></td><td style="text-align:left;">그룹 쓰기 권한 제거</td></tr><tr><td style="text-align:left;"><code>chmod_g+r</code></td><td style="text-align:left;">그룹 읽기 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_g-r</code></td><td style="text-align:left;">그룹 읽기 권한 제거</td></tr></tbody></table><h3 id="기타-사용자-권한-별칭" tabindex="-1">기타 사용자 권한 별칭 <a class="header-anchor" href="#기타-사용자-권한-별칭" aria-label="Permalink to &quot;기타 사용자 권한 별칭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_o+x</code></td><td style="text-align:left;">기타 사용자 실행 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_o-x</code></td><td style="text-align:left;">기타 사용자 실행 권한 제거</td></tr><tr><td style="text-align:left;"><code>chmod_o+w</code></td><td style="text-align:left;">기타 사용자 쓰기 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_o-w</code></td><td style="text-align:left;">기타 사용자 쓰기 권한 제거</td></tr><tr><td style="text-align:left;"><code>chmod_o+r</code></td><td style="text-align:left;">기타 사용자 읽기 권한 추가</td></tr><tr><td style="text-align:left;"><code>chmod_o-r</code></td><td style="text-align:left;">기타 사용자 읽기 권한 제거</td></tr></tbody></table><h3 id="파일-유형-별칭" tabindex="-1">파일 유형 별칭 <a class="header-anchor" href="#파일-유형-별칭" aria-label="Permalink to &quot;파일 유형 별칭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_755d</code></td><td style="text-align:left;">모든 디렉토리 권한을 <code>rwxr-xr-x</code>로 설정</td></tr><tr><td style="text-align:left;"><code>chmod_644f</code></td><td style="text-align:left;">모든 파일 권한을 <code>rw-r--r--</code>로 설정</td></tr></tbody></table><h3 id="재귀-권한-함수" tabindex="-1">재귀 권한 함수 <a class="header-anchor" href="#재귀-권한-함수" aria-label="Permalink to &quot;재귀 권한 함수&quot;">​</a></h3><p><code>change_permission</code> 함수는 확인 프롬프트와 함께 권한을 재귀적으로 적용합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',19)])])}const f=e(o,[["render",i]]);export{g as __pageData,f as default};
